_email" value="<?= e($company['billing_email']??'') ?>"></label><label>Telefon<input name="phone" value="<?= e($company['phone']??'') ?>"></label><label>Website<input type="url" name="website" value="<?= e($company['website']??'https://maison-bebe.ro') ?>"></label></div></section></div><aside><section class="admin-panel"><h2>Serie facturi</h2><label>Prefix<input name="series_prefix" value="<?= e($series[0]['prefix']??'MB') ?>"></label><label>Următorul număr<input type="number" min="1" name="series_next" value="<?= (int)($series[0]['next_number']??1) ?>"></label><label>Zile scadență<input type="number" min="0" name="default_due_days" value="<?= (int)($company['default_due_days']??0) ?>"></label><label>Note implicite<textarea name="default_notes"><?= e($company['default_notes']??'') ?></textarea></label></section><section class="admin-panel"><h2>Cont bancar</h2><label>IBAN<input name="iban" value="<?= e($banks[0]['iban']??'') ?>"></label><label>Bancă<input name="bank_name" value="<?= e($banks[0]['bank_name']??'') ?>"></label><button class="admin-button" type="submit">Salvează datele</button></section></aside></form>
